class Solution {
public:
    int reverse(int x) {
        long long res = 0; // Use long long to handle potential overflow
        while (x != 0) {
            res = res * 10 + x % 10;
            x /= 10;
        }
        // Check for overflow
        if (res > INT_MAX || res < INT_MIN) {
            return 0;
        }
        return static_cast<int>(res);
    }
};
```
